document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("form-mensagem"),t=document.getElementById("resultado");e&&t&&e.addEventListener("submit",async s=>{s.preventDefault();const n=e.querySelector('button[type="submit"]'),a=document.getElementById("id_destinatario"),r=document.getElementById("mensagem");t.classList.remove("show"),t.innerHTML="",n.disabled=!0,n.innerHTML='<span class="spinner-border spinner-border-sm"></span>';const i={id_destinatario:parseInt(a.value),mensagem:r.value.trim()};try{const s=await fetch("../logica/salvar-mensagem.php",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(i)}),n=await s.text(),a=JSON.parse(n),r=a.success?"alert-success":"alert-danger";t.innerHTML=`\n        <div class="alert ${r} alert-dismissible fade show" role="alert">\n          ${a.message}\n          <button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Close"></button>\n        </div>\n      `,a.success&&e.reset()}catch(l){t.innerHTML='\n        <div class="alert alert-danger alert-dismissible fade show" role="alert">\n          Erro ao processar a requisição.\n          <button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Close"></button>\n        </div>\n      '}finally{n.disabled=!1,n.innerHTML="Enviar"}})});
